 (-3.5,0) – (5.5,0) node[right] {$x$};
 (0,-1.5) – (0,6.5) node[above] {$y$};

 (-2.33,1) – (4.33,6);

 ll[AtlasTeal] (-1,2) circle (4pt) node[below left] {$(-1,2)$};
 ll[AtlasTeal] (3,5) circle (4pt) node[above right] {$(3,5)$};

 (-1,2) – (3,2) node[midway, below] { run $= 4$};
 (3,2) – (3,5) node[midway, right] { rise $= 3$};
